// A top-level Verilog interface for a live Verilator simulator

module wctrace_top (
  input clk,
  // client interface with RTEFI, see clients.eps
  input [10:0] len_c,
  input [7:0] idata,
  input raw_l,
  input raw_s,
  output [7:0] odata,
  output [7:0] n_lat_expose  // work around a limitation in Verilator
);

parameter n_lat=10;
assign n_lat_expose = n_lat;

// NOTE: These parameter assignments need to agree with "config.in"
localparam AW = 12;
localparam DW = 20;
localparam TW = 24;

// Bus controller
wire [23:0] addr;
wire [31:0] data_out, data_in;
wire control_strobe, control_rd, control_rd_valid;
mem_gateway #(.n_lat(n_lat)) mem_gateway_i (
  .clk(clk),
  .len_c(len_c), // input [10:0]
  .idata(idata), // input [7:0]
  .raw_l(raw_l), // input
  .raw_s(raw_s), // input
  .odata(odata), // output [7:0]
  .addr(addr), // output [23:0]
  .control_strobe(control_strobe), // output
  .control_rd(control_rd), // output
  .control_rd_valid(control_rd_valid), // output
  .data_out(data_out), // output [31:0]
  .data_in(data_in) // input [31:0]
);

reg [31:0] lb_din=0;
assign data_in = lb_din;

// Configuration ROM (should be at standard LEEP location 0x4000)
wire [15:0] config_rom_out;
config_romx rom (
  .clk(clk), .address(addr[10:0]), .data(config_rom_out)
);

wire [DW-1:0] trace_data;
reg start=1'b0;
wire running;
wire [AW-1:0] pc_mon;
wire [AW-1:0] wctrace_lb_addr = addr[AW-1:0];
wire [31:0] wctrace_lb_out;
wctrace #(
  .AW(AW),
  .DW(DW),
  .TW(TW)
) wctrace_i (
  .clk(clk), // input
  .data(trace_data), // input [DW-1:0]
  .start(start), // input
  .running(running), // output
  .pc_mon(pc_mon), // output [AW-1:0]
  .lb_clk(clk), // input
  .lb_addr(wctrace_lb_addr), // input [AW-1:0]
  .lb_out(wctrace_lb_out) // output [31:0]
);

// Hand-rolled decoder.  This must agree with the hand-written "wctrace_top_regmap.json"
always @(posedge clk) begin
  start <= 1'b0; // strobe
  // Writes (just one strobe in this demo)
  if (control_strobe & (~control_rd)) begin
    casez (addr[15:0])
      16'h1000: start <= data_out[0];
      default: /* do nothing */;
    endcase
  end
  // Reads
  casez (addr[15:0])
    16'b0100_0???_????_????: lb_din <= {16'h0000, config_rom_out};
    16'h1002: lb_din <= {{32-AW{1'b0}}, pc_mon};
    16'h1001: lb_din <= {31'h00000000, running};
    16'h000???: lb_din <= wctrace_lb_out;
    default: lb_din <= 32'hdeadbeef;
  endcase
end

// Fake data for wctrace
reg [DW-5:0] counter=0;
reg [3:0] strobes=4'h0;
always @(posedge clk) begin
  strobes <= 4'h0;
  counter <= counter+1;
  if (counter[3:0] == 4'h0) strobes[0] <= 1'b1;
  if (counter[3:0] == 4'h2) strobes[1] <= 1'b1;
  if (counter[3:0] == 4'h4) strobes[2] <= 1'b1;
  if (counter[3:0] == 4'h8) strobes[3] <= 1'b1;
end

// NOTE: These signal assignments need to agree with "config.in"
assign trace_data[DW-5:0] = counter;
assign trace_data[DW-1-:4] = strobes;

endmodule

// Ultra-stupid layer to define clock domains of signals coming in and out of marble_base
// See cdc_snitch.py
module marble_base_shell(
	// GMII Tx port
	input vgmii_tx_clk,
	output [7:0] vgmii_txd,
	output vgmii_tx_en,
	output vgmii_tx_er,

	// GMII Rx port
	input vgmii_rx_clk,
	input [7:0] vgmii_rxd,
	input vgmii_rx_er,
	input vgmii_rx_dv,

	// Auxiliary I/O and status
	input aux_clk,
	input clk62,
	input cfg_clk,
	output phy_rstn,
	input clk_locked,
	input si570,

	// SPI pins to on-board microcontroller; can give access to configuration
	input SCLK,
	input CSB,
	input MOSI,
	output MISO,
	output mmc_int,

	// SPI boot flash programming port
	output boot_clk,
	output boot_cs,
	output boot_mosi,
	input boot_miso,
	output cfg_d02,

	// One I2C bus; everything gatewayed through a TCA9548A
	// cdc_snitch still gets confused with inout ports like this
	inout  [3:0] twi_scl,
	inout  [3:0] twi_sda,
	inout  TWI_RST,
	input  TWI_INT,

	// White Rabbit compatible DAC subsystem controlling VCXOs
	output WR_DAC_SCLK,
	output WR_DAC_DIN,
	output WR_DAC1_SYNC,
	output WR_DAC2_SYNC,

	// UART to USB
	// The RxD and TxD directions are with respect
	// to the USB/UART chip, not the FPGA!
	// Note that the freq_demo feature doesn't actually use FPGA_TxD.
	// If you don't connect anything to FPGA_RxD, the synthesizer
	// will drop the whole freq_demo feature.
	output FPGA_RxD,
	input FPGA_TxD,

	// Digilent GPS
	input [3:0] GPS,

	// Placeholder for configuring external devices
	output [3:0] ext_config,

	// Simulation-only, please ignore in synthesis
	output in_use,

	// Local bus for an external application
	// Define clock domain
	output lb_clk,
	output [23:0] lb_addr,
	output lb_strobe,
	output lb_rd,
	output lb_write,
	output lb_rd_valid,
	// output [read_pipe_len:0] control_pipe_rd,
	output [31:0] lb_data_out,
	input [31:0] lb_data_in
);

// vgmii Tx
wire [7:0] vgmii_txd_w;
reg [7:0] vgmii_txd_r=0;
wire vgmii_tx_en_w, vgmii_tx_er_w;
reg vgmii_tx_en_r=0, vgmii_tx_er_r=0;
always @(posedge vgmii_tx_clk) begin
	vgmii_txd_r <= vgmii_txd_w;
	vgmii_tx_en_r <= vgmii_tx_en_w;
	vgmii_tx_er_r <= vgmii_tx_er_w;
end
assign vgmii_txd = vgmii_txd_r;
assign vgmii_tx_en = vgmii_tx_en_r;
assign vgmii_tx_er = vgmii_tx_er_r;

// vgmii Rx
(* magic_cdc *) reg [7:0] vgmii_rxd_r=0;
(* magic_cdc *) reg vgmii_rx_dv_r=0, vgmii_rx_er_r=0;
always @(posedge vgmii_rx_clk) begin
	vgmii_rxd_r <= vgmii_rxd;
	vgmii_rx_dv_r <= vgmii_rx_dv;
	vgmii_rx_er_r <= vgmii_rx_er;
end

// Local bus outputs
wire [23:0] lb_addr_w;
reg [23:0] lb_addr_r=0;
wire lb_strobe_w, lb_rd_w, lb_write_w, lb_rd_valid_w;
reg lb_strobe_r=0, lb_rd_r=0, lb_write_r=0, lb_rd_valid_r=0;
wire [31:0] lb_data_out_w;
reg [31:0] lb_data_out_r=0;
always @(posedge lb_clk) begin
	lb_addr_r <= lb_addr_w;
	lb_strobe_r <= lb_strobe_w;
	lb_rd_r <= lb_rd_w;
	lb_write_r <= lb_write_w;
	lb_rd_valid_r <= lb_rd_valid_w;
	lb_data_out_r <= lb_data_out_w;
end
assign lb_addr = lb_addr_r;
assign lb_strobe = lb_strobe_r;
assign lb_rd = lb_rd_r;
assign lb_write = lb_write_r;
assign lb_rd_valid = lb_rd_valid_r;
assign lb_data_out = lb_data_out_r;

// Other inputs
(* magic_cdc *) reg [31:0] lb_data_in_r=0;
(* magic_cdc *) reg [3:0] GPS_r=0;
always @(posedge lb_clk) begin
	lb_data_in_r <= lb_data_in;
	GPS_r <= GPS;
end

// Module under test
marble_base i_mb(
	.vgmii_tx_clk(vgmii_tx_clk),
	.vgmii_txd(vgmii_txd_w),
	.vgmii_tx_en(vgmii_tx_en_w),
	.vgmii_tx_er(vgmii_tx_er_w),
	.vgmii_rx_clk(vgmii_rx_clk),
	.vgmii_rxd(vgmii_rxd_r),
	.vgmii_rx_er(vgmii_rx_er_r),
	.vgmii_rx_dv(vgmii_rx_dv_r),
	.aux_clk(aux_clk),
	.clk62(clk62),
	.cfg_clk(cfg_clk),
	.phy_rstn(phy_rstn),
	.clk_locked(clk_locked),
	.si570(si570),
	.SCLK(SCLK),
	.CSB(CSB),
	.MOSI(MOSI),
	.MISO(MISO),
	.mmc_int(mmc_int),
	.boot_clk(boot_clk),
	.boot_cs(boot_cs),
	.boot_mosi(boot_mosi),
	.boot_miso(boot_miso),
	.cfg_d02(cfg_d02),
	.twi_scl(twi_scl),
	.twi_sda(twi_sda),
	.TWI_RST(TWI_RST),
	.TWI_INT(TWI_INT),
	.WR_DAC_SCLK(WR_DAC_SCLK),
	.WR_DAC_DIN(WR_DAC_DIN),
	.WR_DAC1_SYNC(WR_DAC1_SYNC),
	.WR_DAC2_SYNC(WR_DAC2_SYNC),
	.FPGA_RxD(FPGA_RxD),
	.FPGA_TxD(FPGA_TxD),
	.GPS(GPS_r),
	.ext_config(ext_config),
	.in_use(in_use),
	.lb_clk(lb_clk),
	.lb_addr(lb_addr_w),
	.lb_strobe(lb_strobe_w),
	.lb_rd(lb_rd_w),
	.lb_write(lb_write_w),
	.lb_rd_valid(lb_rd_valid_w),
	.lb_data_out(lb_data_out_w),
	.lb_data_in(lb_data_in_r)
);

endmodule

